675     dec_offset += 64;
676 
677     // Populate key_out (ed25519_sk contains: 32-byte seed + 32-byte public key)
678     key_out-&gt;type = KEY_TYPE_ED25519;
679     memcpy(key_out-&gt;key.ed25519, ed25519_sk, 32);           // Seed (first 32 bytes)
680     memcpy(key_out-&gt;key.ed25519 + 32, ed25519_sk + 32, 32); // Public key (next 32 bytes)
681 
682     // Clean up decrypted data (sensitive!)
683     sodium_memzero(decrypted_blob, decrypted_blob_len);
684     SAFE_FREE(decrypted_blob);
685     SAFE_FREE(key_blob);
686     SAFE_FREE(file_content);
687 
688     log_debug(&quot;Successfully parsed decrypted Ed25519 key&quot;);
689 
690     // Attempt to add the decrypted key to ssh-agent for future password-free use
691     log_debug(&quot;Attempting to add decrypted key to ssh-agent&quot;);
692     asciichat_error_t agent_result = ssh_agent_add_key(key_out, key_path);
693     if (agent_result == ASCIICHAT_OK) {
694       log_debug(&quot;Successfully added key to ssh-agent - password will not be required on next run&quot;);
695     } else {
696       // Non-fatal: key is already decrypted and loaded, just won't be cached in agent
697       log_warn(&quot;Failed to add key to ssh-agent (non-fatal): %s&quot;, asciichat_error_string(agent_result));
698       log_warn(&quot;You can manually add it with: ssh-add %s&quot;, key_path);
699     }
700 
701     return ASCIICHAT_OK;
702   }
703 
704   // Read number of keys
705   if (offset + 4 &gt; key_blob_len) {
706     SAFE_FREE(key_blob);
707     SAFE_FREE(file_content);
708     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key truncated at num keys: %s&quot;, key_path);
709   }
710 
711   uint32_t num_keys = read_u32_be(&amp;key_blob[offset]);
712   offset += 4;
713 
714   log_debug(&quot;num_keys=%u, offset=%zu, key_blob_len=%zu&quot;, num_keys, offset, key_blob_len);
715   log_debug(&quot;Raw bytes at offset %zu: %02x %02x %02x %02x&quot;, offset, key_blob[offset], key_blob[offset + 1],
716             key_blob[offset + 2], key_blob[offset + 3]);
717   log_debug(&quot;After num_keys, offset=%zu&quot;, offset);
718 
719   if (num_keys != 1) {
720     SAFE_FREE(key_blob);
721     SAFE_FREE(file_content);
722     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key contains %u keys (expected 1): %s&quot;, num_keys, key_path);
723   }
724 
725   // Read public key
726   if (offset + 4 &gt; key_blob_len) {
727     SAFE_FREE(key_blob);
728     SAFE_FREE(file_content);
729     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key truncated at pubkey length: %s&quot;, key_path);
730   }
731 
732   log_debug(&quot;About to read pubkey_len at offset=%zu, bytes: %02x %02x %02x %02x&quot;, offset, key_blob[offset],
733             key_blob[offset + 1], key_blob[offset + 2], key_blob[offset + 3]);
734 
735   uint32_t pubkey_len = read_u32_be(&amp;key_blob[offset]);
736   offset += 4;
737 
738   log_debug(&quot;pubkey_len=%u, offset=%zu&quot;, pubkey_len, offset);
739 
740   if (offset + pubkey_len &gt; key_blob_len) {
741     SAFE_FREE(key_blob);
742     SAFE_FREE(file_content);
743     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key truncated at pubkey data: %s&quot;, key_path);
744   }
745 
746   // Parse the public key to extract the Ed25519 public key for validation
747   if (pubkey_len &lt; 4) {
748     SAFE_FREE(key_blob);
749     SAFE_FREE(file_content);
750     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH public key too small: %s&quot;, key_path);
751   }
752 
753   uint32_t key_type_len = read_u32_be(&amp;key_blob[offset]);
754   offset += 4;
755 
756   // Check if it's an Ed25519 key
757   if (key_type_len != 11 || memcmp(key_blob + offset, &quot;ssh-ed25519&quot;, 11) != 0) {
758     SAFE_FREE(key_blob);
759     SAFE_FREE(file_content);
760     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key is not Ed25519: %s&quot;, key_path);
761   }
762 
763   offset += key_type_len; // Skip the key type string
764   log_debug(&quot;After skipping key type, offset=%zu&quot;, offset);
765 
766   // Read the public key length
767   if (offset + 4 &gt; key_blob_len) {
768     SAFE_FREE(key_blob);
769     SAFE_FREE(file_content);
770     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key truncated at public key length: %s&quot;, key_path);
771   }
772 
773   uint32_t pubkey_data_len = read_u32_be(&amp;key_blob[offset]);
774   offset += 4;
775   log_debug(&quot;Public key data length: %u, offset=%zu&quot;, pubkey_data_len, offset);
776 
777   log_debug(&quot;Public key data length: %u (expected 32 for Ed25519)&quot;, pubkey_data_len);
778 
779   // For Ed25519, the public key should be 32 bytes, but let's be more flexible
780   if (pubkey_data_len &lt; 32) {
781     SAFE_FREE(key_blob);
782     SAFE_FREE(file_content);
783     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH public key data too small (%u bytes, expected at least 32): %s&quot;,
784                      pubkey_data_len, key_path);
785   }
786 
787   // Read Ed25519 public key (first 32 bytes) for validation
788   if (offset + 32 &gt; key_blob_len) {
789     SAFE_FREE(key_blob);
790     SAFE_FREE(file_content);
791     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key truncated at public key: %s&quot;, key_path);
792   }
793 
794   uint8_t ed25519_pubkey[32];
795   memcpy(ed25519_pubkey, key_blob + offset, 32);
796   offset += pubkey_data_len; // Skip the entire public key data
797 
798   // Skip the rest of the public key data to get to the private key
799   // We've already parsed: 4 (key_type_len) + 11 (ssh-ed25519) + 4 (pubkey_data_len) + 32 (key) = 51 bytes
800   // So we need to skip the remaining pubkey_len - 51 bytes
801   // Check for underflow before subtraction
802   if (pubkey_len &gt;= 51) {
803     size_t remaining_pubkey = pubkey_len - 51;
804     if (remaining_pubkey &gt; 0) {
805       offset += remaining_pubkey;
806     }
807   }
808 
809   // Read private key
810   if (offset + 4 &gt; key_blob_len) {
811     SAFE_FREE(key_blob);
812     SAFE_FREE(file_content);
813     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key truncated at privkey length: %s&quot;, key_path);
814   }
815 
816   uint32_t privkey_len = read_u32_be(&amp;key_blob[offset]);
817   offset += 4;
818 
819   if (offset + privkey_len &gt; key_blob_len) {
820     SAFE_FREE(key_blob);
821     SAFE_FREE(file_content);
822     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key truncated at privkey data: %s&quot;, key_path);
823   }
824 
825   // Parse the private key structure
826   // Format: [4 bytes: checkint1] [4 bytes: checkint2] [4 bytes: key type length] [key type]
827   //         [4 bytes: public key length] [public key] [4 bytes: private key length] [private key]
828   //         [4 bytes: comment length] [comment]
829 
830   if (privkey_len &lt; 8) {
831     SAFE_FREE(key_blob);
832     SAFE_FREE(file_content);
833     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key data too small: %s&quot;, key_path);
834   }
835 
836   // Verify checkints (should be equal)
837   uint32_t checkint1 = read_u32_be(&amp;key_blob[offset]);
838   uint32_t checkint2 = read_u32_be(&amp;key_blob[offset + 4]);
839   offset += 8;
840 
841   if (checkint1 != checkint2) {
842     SAFE_FREE(key_blob);
843     SAFE_FREE(file_content);
844     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key checkints don't match: %s&quot;, key_path);
845   }
846 
847   // Skip key type
848   if (offset + 4 &gt; key_blob_len) {
849     SAFE_FREE(key_blob);
850     SAFE_FREE(file_content);
851     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key truncated at key type length: %s&quot;, key_path);
852   }
853 
854   uint32_t key_type_len_priv = read_u32_be(&amp;key_blob[offset]);
855   // Check for integer overflow before adding to offset
856   if (key_type_len_priv &gt; key_blob_len || offset + 4 + key_type_len_priv &gt; key_blob_len) {
857     SAFE_FREE(key_blob);
858     SAFE_FREE(file_content);
859     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key type length overflow: %u&quot;, key_type_len_priv);
860   }
861   offset += 4 + key_type_len_priv;
862 
863   // Skip public key
864   if (offset + 4 &gt; key_blob_len) {
865     SAFE_FREE(key_blob);
866     SAFE_FREE(file_content);
867     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key truncated at pubkey length: %s&quot;, key_path);
868   }
869 
870   uint32_t pubkey_len_priv = read_u32_be(&amp;key_blob[offset]);
871   // Check for integer overflow before adding to offset
872   if (pubkey_len_priv &gt; key_blob_len || offset + 4 + pubkey_len_priv &gt; key_blob_len) {
873     SAFE_FREE(key_blob);
874     SAFE_FREE(file_content);
875     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key public key length overflow: %u&quot;, pubkey_len_priv);
876   }
877   offset += 4 + pubkey_len_priv;
878 
879   // Read private key
880   if (offset + 4 &gt; key_blob_len) {
881     SAFE_FREE(key_blob);
882     SAFE_FREE(file_content);
883     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key truncated at privkey length: %s&quot;, key_path);
884   }
885 
886   uint32_t privkey_data_len = read_u32_be(&amp;key_blob[offset]);
887   offset += 4;
888 
889   if (offset + privkey_data_len &gt; key_blob_len) {
890     SAFE_FREE(key_blob);
891     SAFE_FREE(file_content);
892     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key truncated at privkey data: %s&quot;, key_path);
893   }
894 
895   // The private key data should be at least 64 bytes (32 bytes private key + 32 bytes public key)
896   // But OpenSSH format may have additional data
897   if (privkey_data_len &lt; 64) {
898     SAFE_FREE(key_blob);
899     SAFE_FREE(file_content);
900     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key data length is %u (expected at least 64): %s&quot;,
901                      privkey_data_len, key_path);
902   }
903 
904   // Extract the Ed25519 private key (first 32 bytes)
905   uint8_t ed25519_privkey[32];
906   memcpy(ed25519_privkey, key_blob + offset, 32);
907 
908   // Verify the public key matches
909   // The public key in the privkey section is raw Ed25519, while the one in pubkey section is SSH format
910   // We need to compare the raw public key from privkey with the raw public key extracted from pubkey
911   // Use constant-time comparison for cryptographic material
912   if (sodium_memcmp(key_blob + offset + 32, ed25519_pubkey, 32) != 0) {
913     SAFE_FREE(key_blob);
914     SAFE_FREE(file_content);
915     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key public key mismatch: %s&quot;, key_path);
916   }
917 
918   // Initialize the private key structure
919   memset(key_out, 0, sizeof(private_key_t));
920   key_out-&gt;type = KEY_TYPE_ED25519;
921 
922   // Store the actual private key (seed + public key = 64 bytes)
923   // Ed25519 private key format: [32 bytes seed][32 bytes public key]
924   memcpy(key_out-&gt;key.ed25519, ed25519_privkey, 32);     // Store the seed (first 32 bytes)
925   memcpy(key_out-&gt;key.ed25519 + 32, ed25519_pubkey, 32); // Store the public key (next 32 bytes)
926 
927   // Also store the public key in the public_key field for easy access
928   memcpy(key_out-&gt;public_key, ed25519_pubkey, 32);
929 
930   // Set a comment
931   SAFE_STRNCPY(key_out-&gt;key_comment, &quot;ssh-ed25519&quot;, sizeof(key_out-&gt;key_comment) - 1);
932 
933   SAFE_FREE(key_blob);
934   SAFE_FREE(file_content);
935 
936   return ASCIICHAT_OK;
937 }</pre>
