776 
777   log_debug(&quot;Public key data length: %u (expected 32 for Ed25519)&quot;, pubkey_data_len);
778 
779   // For Ed25519, the public key should be 32 bytes, but let's be more flexible
780   if (pubkey_data_len &lt; 32) {
781     SAFE_FREE(key_blob);
782     SAFE_FREE(file_content);
783     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH public key data too small (%u bytes, expected at least 32): %s&quot;,
