855   // Check for integer overflow before adding to offset
856   if (key_type_len_priv &gt; key_blob_len || offset + 4 + key_type_len_priv &gt; key_blob_len) {
857     SAFE_FREE(key_blob);
858     SAFE_FREE(file_content);
859     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key type length overflow: %u&quot;, key_type_len_priv);
860   }
861   offset += 4 + key_type_len_priv;
862 
863   // Skip public key
864   if (offset + 4 &gt; key_blob_len) {
865     SAFE_FREE(key_blob);
866     SAFE_FREE(file_content);
867     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key truncated at pubkey length: %s&quot;, key_path);
868   }
869 
870   uint32_t pubkey_len_priv = read_u32_be(&amp;key_blob[offset]);
871   // Check for integer overflow before adding to offset
872   if (pubkey_len_priv &gt; key_blob_len || offset + 4 + pubkey_len_priv &gt; key_blob_len) {
873     SAFE_FREE(key_blob);
874     SAFE_FREE(file_content);
875     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key public key length overflow: %u&quot;, pubkey_len_priv);
876   }
877   offset += 4 + pubkey_len_priv;
878 
879   // Read private key
880   if (offset + 4 &gt; key_blob_len) {
881     SAFE_FREE(key_blob);
882     SAFE_FREE(file_content);
883     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key truncated at privkey length: %s&quot;, key_path);
884   }
885 
886   uint32_t privkey_data_len = read_u32_be(&amp;key_blob[offset]);
887   offset += 4;
888 
889   if (offset + privkey_data_len &gt; key_blob_len) {
890     SAFE_FREE(key_blob);
891     SAFE_FREE(file_content);
892     return SET_ERRNO(ERROR_CRYPTO_KEY, &quot;OpenSSH private key truncated at privkey data: %s&quot;, key_path);
893   }
894 
895   // The private key data should be at least 64 bytes (32 bytes private key + 32 bytes public key)
896   // But OpenSSH format may have additional data
